INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (21, 6010, "", "", 0, "", "", "vo_minigame_1013_top_talk_6_001", 6, 0, "vo_minigame_1013");
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (11, 6011, 0, 0, 1, 0.8, 0, "マコトさん？\nどうかしましたか？\n何やら不穏な気配を\n感じ取ったのですが", 6, 6, 129911);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (91, 6012, "", "", "", "", "", "", 6, "", 0);
