INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (3, 6014, 1, "", "drama_talk_surprise_loop_shy", "", 0.2, "drama_talk_surprise_in_shy", 6, 0, 129811);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (21, 6015, "", "", 0, "", "", "vo_minigame_1013_top_talk_6_002", 6, 0, "vo_minigame_1013");
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (11, 6016, 0, 0, 1, 0.3, 0, "いやいや何でもない！\nあたしは別に変なこと\n考えてないからな！\nそれより訓練だっ！", 6, 9, 129811);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (91, 6017, "", "", "", "", "", "", 6, "", 0);
