INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (3, 7014, "", "", "", "", 0.2, "drama_talk_thinking", 7, 1, 129911);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (21, 7015, "", "", 0, "", "", "vo_minigame_1013_top_talk_7_002", 7, 0, "vo_minigame_1013");
